function normalizeWebsite(url) {
  if (!url) return '';
  return String(url)
    .trim()
    .toLowerCase()
    .replace(/^https?:\/\//, '')
    .replace(/^www\./, '')
    .replace(/\/+$/, '');
}

const leads = $('Get All Leads').all();
const outreach = $('Get Existing Outreach').all();

const alreadyGenerated = new Set();
for (const item of outreach) {
  if (item.json && item.json.website) {
    alreadyGenerated.add(normalizeWebsite(item.json.website));
  }
}

const filtered = leads.filter(item => {
  const l = item.json;
  const status = String(l.status || '').trim().toLowerCase();
  const scoreNum = parseInt(l.score, 10);
  const email = String(l.email || '').trim();
  const normalizedWebsite = normalizeWebsite(l.website);

  if (status !== 'researched') return false;
  if (isNaN(scoreNum) || scoreNum < 6) return false;
  if (!email || !email.includes('@')) return false;
  if (alreadyGenerated.has(normalizedWebsite)) return false;
  return true;
});

const batch = filtered.slice(0, 8);

console.log('[Copywriter v1.2] Total leads: ' + leads.length);
console.log('[Copywriter v1.2] Already in Outreach (normalized): ' + alreadyGenerated.size);
console.log('[Copywriter v1.2] Matched filter: ' + filtered.length);
console.log('[Copywriter v1.2] Processing batch: ' + batch.length);

return batch;

// Парсим ответ Claude. Режим runOnceForEachItem.
// Оригинальный лид и метаданные лежат в $('Build Claude Request').item.json

const ctx = $('Build Claude Request').item.json;
const lead = ctx._lead;
const emailLang = ctx._email_language;
const possibleName = ctx._possible_name;
const resp = $json;

let subjectA = '';
let subjectB = '';
let preheader = '';
let emailBody = '';
let status = 'draft_ready';
let apiError = '';

function extractJson(text) {
  if (!text) return null;
  let s = String(text).trim();
  if (s.startsWith('```')) {
    s = s.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/, '');
  }
  try { return JSON.parse(s); } catch (e) {}
  const first = s.indexOf('{');
  const last = s.lastIndexOf('}');
  if (first !== -1 && last !== -1 && last > first) {
    const candidate = s.substring(first, last + 1);
    try { return JSON.parse(candidate); } catch (e) {}
  }
  return null;
}

try {
  if (resp && Array.isArray(resp.content) && resp.content[0] && resp.content[0].text) {
    const parsed = extractJson(resp.content[0].text);
    if (parsed) {
      subjectA = parsed.subject_a || '';
      subjectB = parsed.subject_b || '';
      preheader = parsed.preheader || '';
      emailBody = parsed.body || '';
    } else {
      apiError = 'JSON extract failed: ' + String(resp.content[0].text).substring(0, 150);
      status = 'copy_error';
    }
  } else if (resp && resp.type === 'error' && resp.error) {
    apiError = 'Claude API error: ' + (resp.error.type || '') + ' - ' + (resp.error.message || '').substring(0, 200);
    status = 'copy_error';
  } else {
    apiError = 'Unexpected response structure. Keys: ' + Object.keys(resp || {}).join(',').substring(0, 150);
    status = 'copy_error';
  }
} catch (e) {
  apiError = 'Parse exception: ' + String(e.message).substring(0, 150);
  status = 'copy_error';
}

// FAO-трюк отключен в v1.1 — слишком AI-like, заголовки лучше без него
let finalSubjectA = subjectA;

const today = new Date().toISOString().split('T')[0];
const generatedAt = new Date().toISOString();

return {
  // Поля для листа Outreach
  website: lead.website,
  email: lead.email,
  company_name: lead.company_name,
  city: lead.city || '',
  country: lead.country || '',
  language: emailLang,
  score: lead.score || '',
  subject_a: finalSubjectA,
  subject_b: subjectB,
  preheader: preheader,
  body: emailBody,
  generated_at: generatedAt,
  date_generated: today,
  status: status,
  error: apiError,
  // Для обновления статуса лида:
  _lead_website: lead.website,
  _new_lead_status: status === 'draft_ready' ? 'draft_ready' : 'copy_error'
};
